 89→--- /dev/null
 90→+++ b/apps/web/src/app/layouts/MobileLayout.tsx
 91→@@ -0,0 +1,164 @@
 92→+/**
 93→+ * MobileLayout -- single-panel mobile layout with bottom tab bar.
 94→+ *
 95→+ * Replaces the desktop ResizablePanelGroup on screens < 768px.
 96→+ * Two views: Chat (full-width ChatArea) and Code (full-width AllFilesDiffViewer).
 97→+ * Chat is the default -- "AI chat as a first-class citizen".
 98→+ */
 99→+
100→+import { useState, useMemo } from "react";
101→+import type { Dispatch, SetStateAction } from "react";
102→+import type { SessionPanelRef } from "@/features/session";
103→+import { useFileChanges } from "@/features/workspace";
104→+import { AllFilesDiffViewer } from "@/features/workspace/ui/AllFilesDiffViewer";
105→+import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
106→+import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
107→+import type { WorkspaceStatus } from "@shared/enums";
108→+import type { NormalizedTask } from "@/features/workspace/api/workspace.service";
109→+import { cn } from "@/shared/lib/utils";
110→+import { ChatArea } from "./ChatArea";
111→+import { MobileTabBar } from "./MobileTabBar";
112→+import type { MobileTab } from "./MobileTabBar";
113→+import { MobilePRHeaderAction, MobilePRStatusBar } from "./MobilePRBar";
114→+
115→+interface MobileLayoutProps {
116→+  workspace: Workspace;
117→+  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
118→+  sendAgentMessageHandler: ((text: string) => Promise<void>) | null;
119→+  handleSendAgentMessage: (text: string) => void;
120→+  /** Pre-gated by caller: only passed when setup_status === "failed" */
121→+  onRetrySetup?: () => void;
122→+  /** Pre-gated by caller: only passed when setup_status === "failed" */
123→+  onViewSetupLogs?: () => void;
124→+  setCreatePRHandler: (handler: (() => void) | null) => void;
125→+  setSendAgentMessageHandler: Dispatch<
126→+    SetStateAction<((text: string) => Promise<void>) | null>
127→+  >;
128→+  isWatched: boolean;
129→+  manifestTasks?: NormalizedTask[];
130→+  hasManifest?: boolean;
131→+  onRunTask?: (taskName: string) => void;
132→+  onStatusChange?: (status: WorkspaceStatus) => void;
133→+  // PR actions
134→+  prStatus: PRStatus | null;
135→+  ghStatus?: GhCliStatus | null;
136→+  onCreatePR?: () => void;
137→+  onArchive?: () => void;
138→+  targetBranch: string;
139→+  onTargetBranchChange: (branch: string) => void;
140→+}
141→+
142→+export function MobileLayout({
143→+  workspace,
144→+  workspaceChatPanelRef,
145→+  sendAgentMessageHandler,
146→+  handleSendAgentMessage,
147→+  onRetrySetup,
148→+  onViewSetupLogs,
149→+  setCreatePRHandler,
150→+  setSendAgentMessageHandler,
151→+  isWatched,
152→+  manifestTasks,
153→+  hasManifest,
154→+  onRunTask,
155→+  onStatusChange,
156→+  prStatus,
157→+  ghStatus,
158→+  onCreatePR,
159→+  onArchive,
160→+  targetBranch,
161→+  onTargetBranchChange,
162→+}: MobileLayoutProps) {
163→+  const [activeTab, setActiveTab] = useState<MobileTab>("chat");
164→+
165→+  // File changes -- always queried for the badge count on the code tab,
166→+  // and used by AllFilesDiffViewer when the code tab is active.
167→+  const isReady = workspace.state === "ready";
168→+  const { data: fileChangesData } = useFileChanges(
169→+    isReady ? workspace.id : null,
170→+    workspace.session_status,
171→+    isWatched,
172→+    workspace.state
173→+  );
174→+  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);
175→+
176→+  // Shared PR bar props -- avoids repeating the same prop bag twice.
177→+  const prBarProps = {
178→+    prStatus,
179→+    ghStatus,
180→+    onCreatePR,
181→+    onSendAgentMessage: sendAgentMessageHandler ? handleSendAgentMessage : undefined,
182→+    onArchive,
183→+    targetBranch,
184→+    onTargetBranchChange,
185→+    workspacePath: workspace.workspace_path,
186→+    workspaceId: workspace.id,
187→+  };
188→+
189→+  return (
190→+    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
191→+      {/* Header row -- workspace title on left, compact Create PR pill on right */}
192→+      <div className="flex flex-shrink-0 items-center justify-between pr-2">
193→+        <WorkspaceHeader
194→+          title={workspace.title ?? undefined}
195→+          repositoryName={workspace.repo_name}
196→+          branch={workspace.git_branch ?? undefined}
197→+          workspacePath={workspace.workspace_path}
198→+          setupStatus={workspace.setup_status}
199→+          setupError={workspace.error_message}
200→+          onSendAgentMessage={sendAgentMessageHandler ? handleSendAgentMessage : undefined}
201→+          onRetrySetup={onRetrySetup}
202→+          onViewSetupLogs={onViewSetupLogs}
203→+          workspaceStatus={workspace.status}
204→+          onStatusChange={onStatusChange}
205→+          tasks={manifestTasks}
206→+          hasManifest={hasManifest}
207→+          onRunTask={onRunTask}
208→+          mobile
209→+        />
210→+        <MobilePRHeaderAction {...prBarProps} />
211→+      </div>
212→+
213→+      {/* PR status bar -- only shown when a PR exists, 32px */}
214→+      <MobilePRStatusBar {...prBarProps} />
215→+
216→+      {/* Content area -- both views always mounted, inactive hidden via display:none */}
217→+      <div className={cn("flex min-h-0 flex-1 flex-col overflow-hidden", activeTab !== "chat" && "hidden")}
218→+        id="mobile-panel-chat" role="tabpanel">
219→+        <ChatArea
220→+          key={workspace.id}
221→+          workspace={workspace}
222→+          workspaceChatPanelRef={workspaceChatPanelRef}
223→+          onCreatePRHandlerChange={setCreatePRHandler}
224→+          onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
225→+        />
226→+      </div>
227→+
228→+      {/* Code panel -- absolute positioning gives AllFilesDiffViewer's h-full a proper
229→+          height context (h-full doesn't resolve inside flex-grown parents). */}
230→+      <div className={cn("relative min-h-0 flex-1", activeTab !== "code" && "hidden")}
231→+        id="mobile-panel-code" role="tabpanel">
232→+        {fileChanges.length === 0 ? (
233→+          <div className="flex h-full items-center justify-center">
234→+            <p className="text-text-muted text-sm">No file changes yet</p>
235→+          </div>
236→+        ) : (
237→+          <div className="absolute inset-0 overflow-y-auto">
238→+            <AllFilesDiffViewer
239→+              workspaceId={workspace.id}
240→+              fileChanges={fileChanges}
241→+              hideHeader
242→+            />
243→+          </div>
244→+        )}
245→+      </div>
246→+
247→+      {/* Bottom tab bar */}
248→+      <MobileTabBar
249→+        activeTab={activeTab}
250→+        onTabChange={setActiveTab}

