 19→
 20→import { useRef, useCallback, useMemo, useEffect } from "react";
 21→import type { ImperativePanelHandle } from "react-resizable-panels";
 22→import type { SessionPanelRef } from "@/features/session";
 23→import { WelcomeView } from "@/features/repository";
 24→import { useWorkspaceLayout } from "@/features/workspace";
 25→import { useCollapsedSizePercent } from "@/features/workspace/hooks/useCollapsedSizePercent";
 26→import type { RightSideTab } from "@/features/workspace/store";
 27→import { useFileWatcher } from "@/features/file-browser/hooks/useFileWatcher";
 28→import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
 29→import { ContentTabBar, isTabVisible } from "@/features/workspace/ui/ContentTabBar";
 30→import { PRActions } from "@/features/workspace/ui/PRActions";
 31→import { useSettings } from "@/features/settings/api/settings.queries";
 32→import { SidebarInset, useSidebar } from "@/components/ui";
 33→import { cn } from "@/shared/lib/utils";
 34→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 35→import { PanelLeft } from "lucide-react";
 36→import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
 37→import { useUpdateWorkspaceStatus } from "@/features/workspace/api";
 38→import { REVIEW_CODE } from "@/features/session/lib/sessionPrompts";
 39→import { native } from "@/platform";
 40→import { BROWSER_WORKSPACE_CHANGE } from "@shared/events";
 41→import { useBrowserWindowStore } from "@/features/browser/store";
 42→import { track } from "@/platform/analytics";
 43→import { ConnectionBanner, useConnectionState } from "@/features/connection";
 44→import { useIsMobile } from "@/shared/hooks/use-mobile";
 45→import { ChatArea } from "./ChatArea";
 46→import { RightSidePanel } from "./RightSidePanel";
 47→import { MobileLayout } from "./MobileLayout";
 48→import { CollapsedChatStrip, CollapsedContentStrip } from "./CollapsedPanelStrips";
 49→import { useWorkspaceActions } from "./hooks/useWorkspaceActions";
 50→import { usePanelShortcuts } from "./hooks/usePanelShortcuts";
 51→
 52→interface MainContentProps {
 53→  selectedWorkspace: Workspace | null;
 54→  prStatus: PRStatus | null;
 55→  ghStatus?: GhCliStatus | null;
 56→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 57→  onCreateWorkspace: () => void;
 58→  onOpenProject: () => void;
 59→  onCloneRepository: () => void;
 60→}
 61→
 62→export function MainContent({
 63→  selectedWorkspace,
 64→  prStatus,
 65→  ghStatus,
 66→  workspaceChatPanelRef,
 67→  onCreateWorkspace,
 68→  onOpenProject,
 69→  onCloneRepository,
 70→}: MainContentProps) {
 71→  const { open: sidebarOpen, toggleSidebar } = useSidebar();
 72→  const isMobile = useIsMobile();
 73→
 74→  const selectedWorkspaceId = selectedWorkspace?.id ?? null;
 75→  const {
 76→    rightSideTab,
 77→    setRightSideTab,
 78→    chatPanelCollapsed,
 79→    setChatPanelCollapsed,
 80→    rightPanelCollapsed,
 81→    setRightPanelCollapsed,
 82→  } = useWorkspaceLayout(selectedWorkspaceId);
 83→
 84→  // Effective tab: if the stored tab is hidden by experimental settings, fall back to "code".
 85→  const experimentalSettings = useSettings().data;
 86→  const effectiveRightSideTab = isTabVisible(rightSideTab, experimentalSettings)
 87→    ? rightSideTab
 88→    : "code";
 89→
 90→  const isBrowserDetached = useBrowserWindowStore((s) => s.detachedWindowOpen);
 91→  const connectionState = useConnectionState().state;
 92→  const isDisconnected = connectionState === "disconnected";
 93→
 94→  // --- Workspace actions (PR bridge, archive, retry, manifest) ---
 95→  const {
 96→    createPRHandler,
 97→    setCreatePRHandler,
 98→    sendAgentMessageHandler,
 99→    setSendAgentMessageHandler,
100→    selectedTargetBranch,
101→    setSelectedTargetBranch,
102→    handleCreatePR,
103→    handleSendAgentMessage,
104→    handleArchive,
105→    handleRetrySetup,
106→    handleViewSetupLogs,
107→    manifestTasks,
108→    hasManifest,
109→    handleRunTask,
110→  } = useWorkspaceActions({
111→    selectedWorkspace,
112→    setRightSideTab,
113→  });
114→
115→  const statusMutation = useUpdateWorkspaceStatus();
116→
117→  // Only start watching and querying diffs once the worktree checkout is complete.
118→  const isReady = selectedWorkspace?.state === "ready";
119→
120→  // Watch workspace for file changes (event-driven cache invalidation)
121→  const isWatched = useFileWatcher(
122→    isReady ? (selectedWorkspace?.workspace_path ?? null) : null,
123→    isReady ? selectedWorkspaceId : null
124→  );
125→
126→  // --- Refs for imperative panel control ---
127→  const chatPanelRef = useRef<ImperativePanelHandle>(null);
128→  const contentPanelRef = useRef<ImperativePanelHandle>(null);
129→  const panelGroupContainerRef = useRef<HTMLDivElement>(null);
130→
131→  // Dynamic collapsed size: 36px strip -> percentage of container width.
132→  const MIN_PANEL_SIZE = 15;
133→  const collapsedSizePct = useCollapsedSizePercent(panelGroupContainerRef, 36);
134→  const safeCollapsedSize = Math.min(collapsedSizePct, MIN_PANEL_SIZE - 0.1);
135→
136→  // Default split: 40% session / 60% content — same for all tabs.
137→  const sessionPanelDefaultSize = 40;
138→  const contentPanelDefaultSize = 60;
139→
140→  const sessionStatus = selectedWorkspace?.session_status;
141→  const isSessionWorking = sessionStatus === "working";
142→
143→  // --- Content tab change ---
144→  const handleContentTabChange = useCallback(
145→    (tab: RightSideTab) => {
146→      setRightSideTab(tab);
147→      // Track feature surface adoption — fire on every user-initiated tab switch.
148→      // We use a static map instead of ts-pattern here because these are all
149→      // simple string→event mappings with no branching logic.
150→      const tabEventMap: Partial<Record<RightSideTab, () => void>> = {
151→        terminal: () =>
152→          track("terminal_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
153→        browser: () => track("browser_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
154→        simulator: () =>
155→          track("simulator_opened", { workspace_id: selectedWorkspaceId ?? undefined }),
156→        code: () => track("diff_viewed", { workspace_id: selectedWorkspaceId ?? undefined }),
157→      };
158→      tabEventMap[tab]?.();
159→    },
160→    [setRightSideTab, selectedWorkspaceId]
161→  );
162→
163→  // --- Chat panel collapse/expand ---
164→  const handleCollapseChatPanel = useCallback(() => {
165→    setChatPanelCollapsed(true);
166→    chatPanelRef.current?.collapse();
167→  }, [setChatPanelCollapsed]);
168→
169→  const handleExpandChatPanel = useCallback(() => {
170→    setChatPanelCollapsed(false);
171→  }, [setChatPanelCollapsed]);
172→
173→  // --- Content panel collapse/expand ---
174→  const handleCollapseContentPanel = useCallback(() => {
175→    setRightPanelCollapsed(true);
176→    contentPanelRef.current?.collapse();
177→  }, [setRightPanelCollapsed]);
178→
179→  const handleExpandContentPanel = useCallback(() => {
180→    setRightPanelCollapsed(false);
181→  }, [setRightPanelCollapsed]);
182→
183→  // --- Keyboard shortcuts ---
184→  usePanelShortcuts({
185→    enabled: selectedWorkspace !== null && !isMobile,
186→    chatPanelCollapsed,
187→    chatPanelRef,
188→    contentPanelCollapsed: rightPanelCollapsed,
189→    contentPanelRef,
190→  });
191→
192→  // --- Reset panel sizes on workspace switch ---
193→  // ResizablePanelGroup has no key prop — it stays mounted across workspace
194→  // switches so SimulatorPanel and BrowserPanel keep their native sessions alive.
195→  // Without the key, react-resizable-panels won't re-apply defaultSize on
196→  // re-render. We must imperatively collapse/expand panels to match the
197→  // per-workspace Zustand state when the selected workspace changes.
198→  useEffect(() => {
199→    if (!selectedWorkspaceId) return;
200→    if (chatPanelCollapsed) {
201→      chatPanelRef.current?.collapse();
202→    } else {
203→      chatPanelRef.current?.expand();
204→      chatPanelRef.current?.resize(sessionPanelDefaultSize);
205→    }
206→    if (rightPanelCollapsed) {
207→      contentPanelRef.current?.collapse();
208→    } else {
209→      contentPanelRef.current?.expand();
210→      contentPanelRef.current?.resize(contentPanelDefaultSize);
211→    }
212→    // eslint-disable-next-line react-hooks/exhaustive-deps -- only fire on workspace change, not on collapse toggles
213→  }, [selectedWorkspaceId]);
214→
215→  // --- Hide all native BrowserViews on workspace switch ---
216→  // BrowserViews are native Electron overlays rendered ABOVE the DOM. When
217→  // switching workspaces or going to the welcome screen, stale views from
218→  // the previous workspace would remain visible. Hide them immediately;
219→  // the new workspace's BrowserTab will re-show its own view when ready.
220→  useEffect(() => {
221→    native.browserViews.hideAll().catch(() => {});
222→  }, [selectedWorkspaceId]);
223→
224→  // --- Sync workspace changes to detached browser window ---
225→  const detachedWorkspaceContext = useMemo(
226→    () =>
227→      selectedWorkspace
228→        ? {
229→            workspaceId: selectedWorkspace.id,
230→            directoryName: selectedWorkspace.slug,
231→            repoName: selectedWorkspace.repo_name,
232→            branch: selectedWorkspace.git_branch,
233→          }
234→        : null,
235→    [selectedWorkspace]
236→  );
237→
238→  useEffect(() => {
239→    if (!isBrowserDetached || !detachedWorkspaceContext) return;
240→    void native.events.send(BROWSER_WORKSPACE_CHANGE, detachedWorkspaceContext);
241→  }, [isBrowserDetached, detachedWorkspaceContext]);
242→
243→  // Switching to code tab — used by file clicks (diff or preview) in RightSidePanel.
244→  const handleSwitchToCodeTab = useCallback(() => {
245→    setRightSideTab("code");
246→  }, [setRightSideTab]);
247→
248→  // Insert code review prompt into chat input
249→  const handleInsertReviewPrompt = useCallback(() => {
250→    workspaceChatPanelRef.current?.insertText(REVIEW_CODE);
251→  }, [workspaceChatPanelRef]);
252→
253→  return (
254→    <SidebarInset className="min-w-0">
255→      {/* Connection banner — appears at top of content area when WS is down */}
256→      <ConnectionBanner />
257→
258→      <div
259→        data-slot="main-content"
260→        className={cn(
261→          "bg-bg-surface flex h-full min-w-0 flex-1 overflow-hidden border transition-[border-radius,border-color,opacity] duration-[280ms] ease-[cubic-bezier(.19,1,.22,1)]",
262→          sidebarOpen
263→            ? "border-border-subtle rounded-l-xl border-r-0"
264→            : "rounded-none border-transparent",
265→          isDisconnected && "opacity-60"
266→        )}
267→      >
268→        {/* Sidebar toggle -- visible when sidebar collapsed (desktop) or always on mobile welcome */}
269→        {(!sidebarOpen || isMobile) && !selectedWorkspace && (
270→          <button
271→            type="button"
272→            data-slot="welcome-sidebar-toggle"
273→            aria-label="Expand sidebar"
274→            onClick={toggleSidebar}
275→            className="text-muted-foreground/60 hover:text-foreground hover:bg-foreground/5 absolute top-3 left-3 z-10 flex h-7 w-7 items-center justify-center rounded-lg transition-[transform,color,background-color] duration-200 ease-out"
276→          >
277→            <PanelLeft className="h-4 w-4" />
278→          </button>
279→        )}
280→
281→        {selectedWorkspace ? (
282→          isMobile ? (
283→            /* Mobile: single-panel layout with bottom tab bar */
284→            <MobileLayout
285→              key={selectedWorkspace.id}
286→              workspace={selectedWorkspace}
287→              workspaceChatPanelRef={workspaceChatPanelRef}
288→              sendAgentMessageHandler={sendAgentMessageHandler}
289→              handleSendAgentMessage={handleSendAgentMessage}
290→              onRetrySetup={selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined}
291→              onViewSetupLogs={selectedWorkspace.setup_status === "failed" ? handleViewSetupLogs : undefined}
292→              setCreatePRHandler={setCreatePRHandler}
293→              setSendAgentMessageHandler={setSendAgentMessageHandler}
294→              isWatched={isWatched}
295→              manifestTasks={manifestTasks}
296→              hasManifest={hasManifest}
297→              onRunTask={handleRunTask}
298→              onStatusChange={(status) =>
299→                statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
300→              }
301→              prStatus={prStatus}
302→              ghStatus={ghStatus}
303→              onCreatePR={createPRHandler ? handleCreatePR : undefined}
304→              onArchive={handleArchive}
305→              targetBranch={selectedTargetBranch}
306→              onTargetBranchChange={setSelectedTargetBranch}
307→            />
308→          ) : (
309→          /* Two-panel split — the top-level layout, no full-width header */
310→          <div ref={panelGroupContainerRef} className="min-h-0 min-w-0 flex-1">
311→            <ResizablePanelGroup direction="horizontal">
312→              {/* ─── SESSION PANEL (left, collapsible) ─── */}
313→              <ResizablePanel
314→                ref={chatPanelRef}
315→                collapsible
316→                collapsedSize={safeCollapsedSize}
317→                minSize={MIN_PANEL_SIZE}
318→                defaultSize={chatPanelCollapsed ? safeCollapsedSize : sessionPanelDefaultSize}
319→                onCollapse={handleCollapseChatPanel}
320→                onExpand={handleExpandChatPanel}
321→                className="min-w-0"
322→                order={1}
323→              >
324→                {chatPanelCollapsed ? (
325→                  <CollapsedChatStrip
326→                    onExpand={() => chatPanelRef.current?.expand()}
327→                    isWorking={isSessionWorking}
328→                  />
329→                ) : (
330→                  <div className="flex h-full min-w-0 flex-col">
331→                    {/* Title header — workspace name + repo/branch + Open */}
332→                    <WorkspaceHeader
333→                      title={selectedWorkspace.title ?? undefined}
334→                      repositoryName={selectedWorkspace.repo_name}
335→                      branch={selectedWorkspace.git_branch ?? undefined}
336→                      workspacePath={selectedWorkspace.workspace_path}
337→                      setupStatus={selectedWorkspace.setup_status}
338→                      setupError={selectedWorkspace.error_message}
339→                      onSendAgentMessage={
340→                        sendAgentMessageHandler ? handleSendAgentMessage : undefined
341→                      }
342→                      onRetrySetup={
343→                        selectedWorkspace.setup_status === "failed" ? handleRetrySetup : undefined
344→                      }
345→                      onViewSetupLogs={
346→                        selectedWorkspace.setup_status === "failed"
347→                          ? handleViewSetupLogs
348→                          : undefined
349→                      }
350→                      workspaceStatus={selectedWorkspace.status}
351→                      onStatusChange={(status) =>
352→                        statusMutation.mutate({ workspaceId: selectedWorkspace.id, status })
353→                      }
354→                      tasks={manifestTasks}
355→                      hasManifest={hasManifest}
356→                      onRunTask={handleRunTask}
357→                    />
358→
359→                    {/* Session tabs + chat messages + input */}
360→                    <ChatArea
361→                      key={selectedWorkspace.id}
362→                      workspace={selectedWorkspace}
363→                      workspaceChatPanelRef={workspaceChatPanelRef}
364→                      onCreatePRHandlerChange={setCreatePRHandler}
365→                      onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
366→                      onCollapseChatPanel={handleCollapseChatPanel}
367→                    />
368→                  </div>
369→                )}
370→              </ResizablePanel>
371→
372→              <ResizableHandle />
373→
374→              {/* ─── CONTENT PANEL (right, collapsible) ─── */}
375→              <ResizablePanel
376→                ref={contentPanelRef}
377→                collapsible
378→                collapsedSize={safeCollapsedSize}
379→                defaultSize={rightPanelCollapsed ? safeCollapsedSize : contentPanelDefaultSize}
380→                minSize={MIN_PANEL_SIZE}
381→                onCollapse={handleCollapseContentPanel}
382→                onExpand={handleExpandContentPanel}
383→                className="min-w-0"
384→                order={2}
385→              >
386→                {rightPanelCollapsed ? (
387→                  <CollapsedContentStrip onExpand={() => contentPanelRef.current?.expand()} />
388→                ) : (
389→                  <div className="flex h-full flex-col pr-2 pb-2">
390→                    {/* Tab header: content tabs (left) + PR actions (right) */}
391→                    <div className="drag-region flex h-11 flex-shrink-0 items-center justify-between px-2.5">
392→                      <ContentTabBar
393→                        activeTab={effectiveRightSideTab}
394→                        onTabChange={handleContentTabChange}
395→                        workspaceId={selectedWorkspaceId}
396→                      />
397→                      <PRActions
398→                        prStatus={prStatus}
399→                        ghStatus={ghStatus}
400→                        onCreatePR={createPRHandler ? handleCreatePR : undefined}
401→                        onSendAgentMessage={
402→                          sendAgentMessageHandler ? handleSendAgentMessage : undefined
403→                        }
404→                        onArchive={handleArchive}
405→                        targetBranch={selectedTargetBranch}
406→                        onTargetBranchChange={setSelectedTargetBranch}
407→                        workspacePath={selectedWorkspace.workspace_path}
408→                        workspaceId={selectedWorkspaceId ?? undefined}
409→                      />
410→                    </div>
411→
412→                    {/* Content area — rounded corners, subtle border */}
413→                    <div className="border-border-subtle bg-bg-elevated flex min-h-0 flex-1 overflow-hidden rounded-lg border">
414→                      <RightSidePanel
415→                        workspace={selectedWorkspace}
416→                        activeTab={effectiveRightSideTab}
417→                        onSwitchToCodeTab={handleSwitchToCodeTab}
418→                        isWatched={isWatched}
419→                        onReview={handleInsertReviewPrompt}
420→                      />
421→                    </div>
422→                  </div>
423→                )}
424→              </ResizablePanel>
425→            </ResizablePanelGroup>
426→          </div>
427→          )
428→        ) : (
429→          <div className="flex min-w-0 flex-1">
430→            <WelcomeView
431→              onCreateWorkspace={onCreateWorkspace}
432→              onOpenProject={onOpenProject}
433→              onCloneRepository={onCloneRepository}
434→            />
435→          </div>
436→        )}
437→      </div>
438→    </SidebarInset>
439→  );
440→}
441→

