 1→import * as React from "react";
 2→
 3→import { cn } from "@/shared/lib/utils";
 4→
 5→// Some engines don't support field-sizing: content.
 6→// Detect once so we can fall back to JS-based auto-resize.
 7→const supportsFieldSizing = typeof CSS !== "undefined" && CSS.supports("field-sizing", "content");
 8→
 9→const Textarea = React.forwardRef<HTMLTextAreaElement, React.ComponentPropsWithoutRef<"textarea">>(
10→  ({ className, ...props }, forwardedRef) => {
11→    const internalRef = React.useRef<HTMLTextAreaElement | null>(null);
12→
13→    const setRef = React.useCallback(
14→      (el: HTMLTextAreaElement | null) => {
15→        internalRef.current = el;
16→        if (typeof forwardedRef === "function") forwardedRef(el);
17→        else if (forwardedRef) forwardedRef.current = el;
18→      },
19→      [forwardedRef]
20→    );
21→
22→    const resize = React.useCallback(() => {
23→      if (supportsFieldSizing) return;
24→      const el = internalRef.current;
