/* ============================================
   Markdown Content Styles - Jony Ive Philosophy
   "Simplicity is about subtracting the obvious"

   Design Principles:
   - Tight density (minimal waste)
   - Subtle colors (no harsh pure white/black)
   - Small code (13px base, compact padding)
   - Clear hierarchy without shouting
   ============================================ */

/* Base markdown container - Dense IDE typography (13px base) */
.markdown-content {
  font-size: 13px;
  line-height: 1.5;
  letter-spacing: -0.011em;
  color: var(--foreground);
  word-break: break-word;
}

/* Headings - Progressive hierarchy with scaled margins and per-level typography.
   Asymmetric margins: large top (section break signal), small bottom (binds to content).
   Line-height decreases with heading importance (tighter at large sizes). */
.markdown-content h1,
.markdown-content h2,
.markdown-content h3,
.markdown-content h4,
.markdown-content h5,
.markdown-content h6 {
  color: var(--foreground);
  font-weight: 600;
  text-wrap: balance;
}

.markdown-content h1 {
  font-size: 22px;
  font-weight: 650;
  line-height: 1.2;
  letter-spacing: -0.022em;
  margin-top: 1.5rem; /* 24px */
  margin-bottom: 0.375rem; /* 6px */
}

.markdown-content h2 {
  font-size: 17px;
  line-height: 1.25;
  letter-spacing: -0.018em;
  margin-top: 1.25rem; /* 20px */
  margin-bottom: 0.25rem; /* 4px */
}

.markdown-content h3 {
  font-size: 15px;
  line-height: 1.3;
  letter-spacing: -0.014em;
  margin-top: 1rem; /* 16px */
  margin-bottom: 0.25rem; /* 4px */
}

.markdown-content h4 {
  font-size: 13px;
  line-height: 1.35;
  letter-spacing: -0.011em;
  margin-top: 0.75rem; /* 12px */
  margin-bottom: 0.125rem; /* 2px */
}

.markdown-content h5 {
  font-size: 12px;
  line-height: 1.4;
  letter-spacing: -0.006em;
  margin-top: 0.75rem; /* 12px */
  margin-bottom: 0.125rem; /* 2px */
}

/* h6 — uppercase label texture at sub-body size, distinct from h5 through
   case + wide tracking + muted color instead of size alone */
.markdown-content h6 {
  font-size: 11px;
  line-height: 1.45;
  letter-spacing: 0.03em;
  text-transform: uppercase;
  color: var(--muted-foreground);
  margin-top: 0.5rem; /* 8px */
  margin-bottom: 0.125rem; /* 2px */
}

/* First heading has no top margin */
.markdown-content > :first-child {
  margin-top: 0;
}

/* Last element has no bottom margin */
.markdown-content > :last-child {
  margin-bottom: 0;
}

/* Prevent double-spacing from markdown line breaks (Cursor pattern).
   Scoped to paragraphs to avoid affecting <br> in code blocks or pre. */
.markdown-content p br {
  display: none;
}

/* Paragraphs - Tight spacing (4px like Codex) */
.markdown-content p {
  margin-top: 0.25rem;
  margin-bottom: 0.25rem;
}

/* Strong and emphasis */
.markdown-content strong {
  font-weight: 600; /* Semibold - emphasis without being too heavy */
  color: var(--foreground);
}

.markdown-content em {
  font-style: italic;
  color: color-mix(in oklch, var(--foreground) 90%, transparent);
}

/* Links */
.markdown-content a {
  color: var(--primary);
  text-decoration: underline;
  text-decoration-color: color-mix(in oklch, var(--primary) 40%, transparent);
  text-underline-offset: 2px;
}

/* Hover effects only on devices with hover capability (not touch screens) */
@media (hover: hover) and (pointer: fine) {
  .markdown-content a {
    transition: opacity 200ms ease;
  }
  .markdown-content a:hover {
    opacity: 0.7;
    text-decoration-color: var(--primary);
  }
}

/* Disable transitions for users who prefer reduced motion */
@media (prefers-reduced-motion: reduce) {
  .markdown-content a {
    transition: none;
  }
}

/* Lists - Compact with visible bullets */
.markdown-content ul,
.markdown-content ol {
  margin-top: 0.25rem;
  margin-bottom: 0.5rem;
  padding-left: 1.125rem;
}

.markdown-content ul {
  list-style-type: disc;
}

.markdown-content ol {
  list-style-type: decimal;
}

.markdown-content li {
  margin-top: 0.125rem; /* Reduced from 0.25rem */
  margin-bottom: 0.125rem;
}

/* Nested lists */
.markdown-content ul ul,
.markdown-content ol ul {
  list-style-type: circle;
  margin-top: 0.125rem;
  margin-bottom: 0.125rem;
}

.markdown-content ul ul ul,
.markdown-content ol ul ul,
.markdown-content ol ol ul {
  list-style-type: square;
}

/* List markers - Subtle but visible */
.markdown-content li::marker {
  color: color-mix(in oklch, var(--foreground) 50%, transparent);
}

/* Blockquotes - Minimal */
.markdown-content blockquote {
  margin-top: 0.75rem;
  margin-bottom: 0.75rem;
  padding-left: 0.75rem; /* Reduced from 1rem */
  border-left: 2px solid color-mix(in oklch, var(--foreground) 12%, transparent);
  color: var(--muted-foreground);
  font-style: italic;
}

/* Horizontal rule — gradient fade (transparent edges → 50% border → transparent).
   Softer than a solid line; subordinate to headings in visual hierarchy. */
.markdown-content hr {
  margin-top: 1rem;
  margin-bottom: 1rem;
  border: none;
  height: 1px;
  background: linear-gradient(
    to right,
    transparent,
    color-mix(in oklch, var(--border) 50%, transparent) 15%,
    color-mix(in oklch, var(--border) 50%, transparent) 85%,
    transparent
  );
}

/* Inline code - Subtle pill */
.markdown-content code:not(pre code) {
  font-family: var(--font-family-mono);
  font-size: 0.85em; /* ~11px from 13px base */
  letter-spacing: 0em; /* Reset: mono must not inherit body's -0.011em */
  padding: 0.125rem 0.375rem;
  background-color: color-mix(in oklch, var(--muted) 60%, transparent);
  border-radius: var(--radius-xs);
  color: color-mix(in oklch, var(--foreground) 90%, transparent);
}

/* Code blocks - COMPACT (12px, less padding) */
.markdown-content pre {
  margin-top: 0.75rem; /* Reduced from 1rem */
  margin-bottom: 0.75rem;
  padding: 0.75rem 0.75rem;
  overflow-x: auto;
  border-radius: var(--radius-sm);
  background-color: var(--bg-code);
  font-family: var(--font-family-mono);
  font-size: 12px;
  line-height: 1.5;
  letter-spacing: 0em;
}

.markdown-content pre code {
  font-family: var(--font-family-mono);
  background: transparent;
  padding: 0;
  border-radius: 0;
  font-size: inherit;
  color: var(--foreground);
}

/* Tables - Compact */
.markdown-content table {
  margin-top: 0.75rem;
  margin-bottom: 0.75rem;
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}

.markdown-content th,
.markdown-content td {
  padding: 0.375rem 0.5rem; /* Reduced from 0.5rem 0.75rem */
  border: 1px solid color-mix(in oklch, var(--border) 60%, transparent);
  text-align: left;
}

.markdown-content th {
  font-weight: 600;
  background-color: color-mix(in oklch, var(--muted) 40%, transparent);
}

.markdown-content tr:nth-child(even) {
  background-color: color-mix(in oklch, var(--muted) 20%, transparent);
}

/* Task lists (GFM) */
.markdown-content input[type="checkbox"] {
  margin-right: 0.375rem; /* Reduced from 0.5rem */
}

/* Images */
.markdown-content img {
  max-width: 100%;
  height: auto;
  border-radius: var(--radius-sm);
  margin-top: 0.75rem;
  margin-bottom: 0.75rem;
}

/* Squircle progressive enhancement — Apple-style continuous-curvature corners.
 * superellipse(1.5) produces iOS/macOS squircle shape.
 * --corner-radius-scale bumps ALL --radius-* tokens to 1.25× because squircle
 * corners look visually tighter than standard border-radius at the same pixel
 * value. corner-shape is applied to sm→4xl Tailwind classes; 2xs/xs are too
 * small to benefit and full is a pill. Elements consuming var(--radius-*)
 * directly in CSS (scrollbars, diff components, markdown) get the inflated
 * radius without squircle — the 1-2px delta is imperceptible. */
@supports (corner-shape: superellipse(1.5)) {
  :root {
    --corner-radius-scale: 1.25;
  }
  .rounded-sm,
  .rounded-md,
  .rounded-lg,
  .rounded-xl,
  .rounded-2xl,
  .rounded-3xl,
  .rounded-4xl {
    corner-shape: superellipse(1.5);
  }
}

/**
 * MobileLayout -- single-panel mobile layout with bottom tab bar.
 *
 * Replaces the desktop ResizablePanelGroup on screens < 768px.
 * Two views: Chat (full-width ChatArea) and Code (full-width AllFilesDiffViewer).
 * Chat is the default -- "AI chat as a first-class citizen".
 */

import { useState, useMemo } from "react";
import type { Dispatch, SetStateAction } from "react";
import type { SessionPanelRef } from "@/features/session";
import { useFileChanges } from "@/features/workspace";
import { AllFilesDiffViewer } from "@/features/workspace/ui/AllFilesDiffViewer";
import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import type { NormalizedTask } from "@/features/workspace/api/workspace.service";
import { cn } from "@/shared/lib/utils";
import { ChatArea } from "./ChatArea";
import { MobileTabBar } from "./MobileTabBar";
import type { MobileTab } from "./MobileTabBar";
import { MobilePRHeaderAction, MobilePRStatusBar } from "./MobilePRBar";

interface MobileLayoutProps {
  workspace: Workspace;
  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
  sendAgentMessageHandler: ((text: string) => Promise<void>) | null;
  handleSendAgentMessage: (text: string) => void;
  /** Pre-gated by caller: only passed when setup_status === "failed" */
  onRetrySetup?: () => void;
  /** Pre-gated by caller: only passed when setup_status === "failed" */
  onViewSetupLogs?: () => void;
  setCreatePRHandler: (handler: (() => void) | null) => void;
  setSendAgentMessageHandler: Dispatch<SetStateAction<((text: string) => Promise<void>) | null>>;
  isWatched: boolean;
  manifestTasks?: NormalizedTask[];
  hasManifest?: boolean;
  onRunTask?: (taskName: string) => void;
  onStatusChange?: (status: WorkspaceStatus) => void;
  // PR actions
  prStatus: PRStatus | null;
  ghStatus?: GhCliStatus | null;
  onCreatePR?: () => void;
  onArchive?: () => void;
  targetBranch: string;
  onTargetBranchChange: (branch: string) => void;
}

export function MobileLayout({
  workspace,
  workspaceChatPanelRef,
  sendAgentMessageHandler,
  handleSendAgentMessage,
  onRetrySetup,
  onViewSetupLogs,
  setCreatePRHandler,
  setSendAgentMessageHandler,
  isWatched,
  manifestTasks,
  hasManifest,
  onRunTask,
  onStatusChange,
  prStatus,
  ghStatus,
  onCreatePR,
  onArchive,
  targetBranch,
  onTargetBranchChange,
}: MobileLayoutProps) {
  const [activeTab, setActiveTab] = useState<MobileTab>("chat");

  // File changes -- always queried for the badge count on the code tab,
  // and used by AllFilesDiffViewer when the code tab is active.
  const isReady = workspace.state === "ready";
  const { data: fileChangesData } = useFileChanges(
    isReady ? workspace.id : null,
    workspace.session_status,
    isWatched,
    workspace.state
  );
  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);

  // Shared PR bar props -- avoids repeating the same prop bag twice.
  const prBarProps = {
    prStatus,
    ghStatus,
    onCreatePR,
    onSendAgentMessage: sendAgentMessageHandler ? handleSendAgentMessage : undefined,
    onArchive,
    targetBranch,
    onTargetBranchChange,
    workspacePath: workspace.workspace_path,
    workspaceId: workspace.id,
  };

  return (
    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
      {/* Header row -- workspace title on left, compact Create PR pill on right */}
      <div className="flex flex-shrink-0 items-center justify-between pr-2">
        <WorkspaceHeader
          title={workspace.title ?? undefined}
          repositoryName={workspace.repo_name}
          branch={workspace.git_branch ?? undefined}
          workspacePath={workspace.workspace_path}
          setupStatus={workspace.setup_status}
          setupError={workspace.error_message}
          onSendAgentMessage={sendAgentMessageHandler ? handleSendAgentMessage : undefined}
          onRetrySetup={onRetrySetup}
          onViewSetupLogs={onViewSetupLogs}
          workspaceStatus={workspace.status}
          onStatusChange={onStatusChange}
          tasks={manifestTasks}
          hasManifest={hasManifest}
          onRunTask={onRunTask}
          mobile
        />
        <MobilePRHeaderAction {...prBarProps} />
      </div>

      {/* PR status bar -- only shown when a PR exists, 32px */}
      <MobilePRStatusBar {...prBarProps} />

      {/* Content area -- both views always mounted, inactive hidden via display:none */}
      <div
        className={cn(
          "flex min-h-0 flex-1 flex-col overflow-hidden",
          activeTab !== "chat" && "hidden"
        )}
        id="mobile-panel-chat"
        role="tabpanel"
        aria-labelledby="mobile-tab-chat"
      >
        <ChatArea
          key={workspace.id}
          workspace={workspace}
          workspaceChatPanelRef={workspaceChatPanelRef}
          onCreatePRHandlerChange={setCreatePRHandler}
          onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
        />
      </div>

      {/* Code panel -- absolute positioning gives AllFilesDiffViewer's h-full a proper
          height context (h-full doesn't resolve inside flex-grown parents). */}
      <div
        className={cn("relative min-h-0 flex-1", activeTab !== "code" && "hidden")}
        id="mobile-panel-code"
        role="tabpanel"
        aria-labelledby="mobile-tab-code"
      >
        {fileChanges.length === 0 ? (
          <div className="flex h-full items-center justify-center">
            <p className="text-text-muted text-sm">No file changes yet</p>
          </div>
        ) : (
          <div className="absolute inset-0 overflow-y-auto">
            <AllFilesDiffViewer workspaceId={workspace.id} fileChanges={fileChanges} hideHeader />
          </div>
        )}
      </div>

      {/* Bottom tab bar */}
      <MobileTabBar
        activeTab={activeTab}
        onTabChange={setActiveTab}
        fileChangesCount={fileChanges.length}
      />
    </div>
  );
}

