  1→/**
  2→ * MobileLayout -- single-panel mobile layout with bottom tab bar.
  3→ *
  4→ * Replaces the desktop ResizablePanelGroup on screens < 768px.
  5→ * Two views: Chat (full-width ChatArea) and Code (full-width AllFilesDiffViewer).
  6→ * Chat is the default -- "AI chat as a first-class citizen".
  7→ */
  8→
  9→import { useState, useMemo } from "react";
 10→import type { Dispatch, SetStateAction } from "react";
 11→import type { SessionPanelRef } from "@/features/session";
 12→import { useFileChanges } from "@/features/workspace";
 13→import { AllFilesDiffViewer } from "@/features/workspace/ui/AllFilesDiffViewer";
 14→import { WorkspaceHeader } from "@/features/workspace/ui/WorkspaceHeader";
 15→import type { Workspace, PRStatus, GhCliStatus } from "@/shared/types";
 16→import type { WorkspaceStatus } from "@shared/enums";
 17→import type { NormalizedTask } from "@/features/workspace/api/workspace.service";
 18→import { cn } from "@/shared/lib/utils";
 19→import { ChatArea } from "./ChatArea";
 20→import { MobileTabBar } from "./MobileTabBar";
 21→import type { MobileTab } from "./MobileTabBar";
 22→import { MobilePRHeaderAction, MobilePRStatusBar } from "./MobilePRBar";
 23→
 24→interface MobileLayoutProps {
 25→  workspace: Workspace;
 26→  workspaceChatPanelRef: React.MutableRefObject<SessionPanelRef | null>;
 27→  sendAgentMessageHandler: ((text: string) => Promise<void>) | null;
 28→  handleSendAgentMessage: (text: string) => void;
 29→  /** Pre-gated by caller: only passed when setup_status === "failed" */
 30→  onRetrySetup?: () => void;
 31→  /** Pre-gated by caller: only passed when setup_status === "failed" */
 32→  onViewSetupLogs?: () => void;
 33→  setCreatePRHandler: (handler: (() => void) | null) => void;
 34→  setSendAgentMessageHandler: Dispatch<SetStateAction<((text: string) => Promise<void>) | null>>;
 35→  isWatched: boolean;
 36→  manifestTasks?: NormalizedTask[];
 37→  hasManifest?: boolean;
 38→  onRunTask?: (taskName: string) => void;
 39→  onStatusChange?: (status: WorkspaceStatus) => void;
 40→  // PR actions
 41→  prStatus: PRStatus | null;
 42→  ghStatus?: GhCliStatus | null;
 43→  onCreatePR?: () => void;
 44→  onArchive?: () => void;
 45→  targetBranch: string;
 46→  onTargetBranchChange: (branch: string) => void;
 47→}
 48→
 49→export function MobileLayout({
 50→  workspace,
 51→  workspaceChatPanelRef,
 52→  sendAgentMessageHandler,
 53→  handleSendAgentMessage,
 54→  onRetrySetup,
 55→  onViewSetupLogs,
 56→  setCreatePRHandler,
 57→  setSendAgentMessageHandler,
 58→  isWatched,
 59→  manifestTasks,
 60→  hasManifest,
 61→  onRunTask,
 62→  onStatusChange,
 63→  prStatus,
 64→  ghStatus,
 65→  onCreatePR,
 66→  onArchive,
 67→  targetBranch,
 68→  onTargetBranchChange,
 69→}: MobileLayoutProps) {
 70→  const [activeTab, setActiveTab] = useState<MobileTab>("chat");
 71→
 72→  // File changes -- always queried for the badge count on the code tab,
 73→  // and used by AllFilesDiffViewer when the code tab is active.
 74→  const isReady = workspace.state === "ready";
 75→  const { data: fileChangesData } = useFileChanges(
 76→    isReady ? workspace.id : null,
 77→    workspace.session_status,
 78→    isWatched,
 79→    workspace.state
 80→  );
 81→  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);
 82→
 83→  // Shared PR bar props -- avoids repeating the same prop bag twice.
 84→  const prBarProps = {
 85→    prStatus,
 86→    ghStatus,
 87→    onCreatePR,
 88→    onSendAgentMessage: sendAgentMessageHandler ? handleSendAgentMessage : undefined,
 89→    onArchive,
 90→    targetBranch,
 91→    onTargetBranchChange,
 92→    workspacePath: workspace.workspace_path,
 93→    workspaceId: workspace.id,
 94→  };
 95→
 96→  return (
 97→    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
 98→      {/* Header row -- workspace title on left, compact Create PR pill on right */}
 99→      <div className="flex flex-shrink-0 items-center justify-between pr-2">
100→        <WorkspaceHeader
101→          title={workspace.title ?? undefined}
102→          repositoryName={workspace.repo_name}
103→          branch={workspace.git_branch ?? undefined}
104→          workspacePath={workspace.workspace_path}
105→          setupStatus={workspace.setup_status}
106→          setupError={workspace.error_message}
107→          onSendAgentMessage={sendAgentMessageHandler ? handleSendAgentMessage : undefined}
108→          onRetrySetup={onRetrySetup}
109→          onViewSetupLogs={onViewSetupLogs}
110→          workspaceStatus={workspace.status}
111→          onStatusChange={onStatusChange}
112→          tasks={manifestTasks}
113→          hasManifest={hasManifest}
114→          onRunTask={onRunTask}
115→          mobile
116→        />
117→        <MobilePRHeaderAction {...prBarProps} />
118→      </div>
119→
120→      {/* PR status bar -- only shown when a PR exists, 32px */}
121→      <MobilePRStatusBar {...prBarProps} />
122→
123→      {/* Content area -- both views always mounted, inactive hidden via display:none */}
124→      <div
125→        className={cn(
126→          "flex min-h-0 flex-1 flex-col overflow-hidden",
127→          activeTab !== "chat" && "hidden"
128→        )}
129→        id="mobile-panel-chat"
130→        role="tabpanel"
131→        aria-labelledby="mobile-tab-chat"
132→      >
133→        <ChatArea
134→          key={workspace.id}
135→          workspace={workspace}
136→          workspaceChatPanelRef={workspaceChatPanelRef}
137→          onCreatePRHandlerChange={setCreatePRHandler}
138→          onSendAgentMessageHandlerChange={setSendAgentMessageHandler}
139→        />
140→      </div>
141→
142→      {/* Code panel -- absolute positioning gives AllFilesDiffViewer's h-full a proper
143→          height context (h-full doesn't resolve inside flex-grown parents). */}
144→      <div
145→        className={cn("relative min-h-0 flex-1", activeTab !== "code" && "hidden")}
146→        id="mobile-panel-code"
147→        role="tabpanel"
148→        aria-labelledby="mobile-tab-code"
149→      >
150→        {fileChanges.length === 0 ? (
151→          <div className="flex h-full items-center justify-center">
152→            <p className="text-text-muted text-sm">No file changes yet</p>
153→          </div>
154→        ) : (
155→          <div className="absolute inset-0 overflow-y-auto">
156→            <AllFilesDiffViewer workspaceId={workspace.id} fileChanges={fileChanges} hideHeader />
157→          </div>
158→        )}
159→      </div>
160→
161→      {/* Bottom tab bar */}
162→      <MobileTabBar
163→        activeTab={activeTab}
164→        onTabChange={setActiveTab}
165→        fileChangesCount={fileChanges.length}
166→      />
167→    </div>
168→  );
169→}
