 1→/**
 2→ * MobileTabBar -- bottom navigation for mobile web layout.
 3→ *
 4→ * Two tabs: Chat (default) and Code (all-files diff viewer).
 5→ * Badge dot on Code tab when file changes exist.
 6→ * Fixed at the bottom of the mobile flex column (not position:fixed).
 7→ * Safe-area aware for notched iOS devices.
 8→ */
 9→
10→import { MessageSquare, GitBranch } from "lucide-react";
11→import { cn } from "@/shared/lib/utils";
12→
13→export type MobileTab = "chat" | "code";
14→
15→interface MobileTabBarProps {
16→  activeTab: MobileTab;
17→  onTabChange: (tab: MobileTab) => void;
18→  fileChangesCount: number;
19→}
20→
21→const tabs: Array<{ id: MobileTab; label: string; icon: typeof MessageSquare }> = [
22→  { id: "chat", label: "Chat", icon: MessageSquare },
23→  { id: "code", label: "Code", icon: GitBranch },
24→];
25→
26→export function MobileTabBar({ activeTab, onTabChange, fileChangesCount }: MobileTabBarProps) {
27→  return (
28→    <div
29→      data-slot="mobile-tab-bar"
30→      role="tablist"
31→      aria-label="View"
32→      className="border-border-subtle bg-bg-surface flex min-h-12 flex-shrink-0 items-start border-t pt-2 pb-[env(safe-area-inset-bottom)]"
33→    >
34→      {tabs.map((tab) => {
35→        const Icon = tab.icon;
36→        const isActive = activeTab === tab.id;
37→        const showBadge = tab.id === "code" && fileChangesCount > 0;
38→
39→        return (
40→          <button
41→            key={tab.id}
42→            id={`mobile-tab-${tab.id}`}
43→            type="button"
44→            role="tab"
45→            aria-selected={isActive}
46→            aria-controls={`mobile-panel-${tab.id}`}
47→            tabIndex={isActive ? 0 : -1}
48→            onClick={() => onTabChange(tab.id)}
49→            className={cn(
50→              "relative flex flex-1 flex-col items-center justify-center gap-0.5 transition-colors duration-150",
51→              isActive ? "text-foreground" : "text-text-muted"
52→            )}
53→          >
54→            <div className="relative">
55→              <Icon className="h-[18px] w-[18px]" />
56→              {showBadge && (
57→                <span className="bg-primary text-primary-foreground absolute -top-1.5 -right-2.5 flex h-4 min-w-4 items-center justify-center rounded-full px-1 text-[9px] leading-none font-bold">
58→                  {fileChangesCount > 99 ? "99+" : fileChangesCount}
59→                </span>
60→              )}
61→            </div>
62→            <span className="text-[10px] font-medium">{tab.label}</span>
63→          </button>
64→        );
65→      })}
66→    </div>
67→  );
68→}
