 21→  onCreatePRHandlerChange: (handler: (() => void) | null) => void;
 22→  onSendAgentMessageHandlerChange: Dispatch<
 23→    SetStateAction<((text: string) => Promise<void>) | null>
 24→  >;
 25→  onCollapseChatPanel?: () => void;
 26→}
 27→
 28→export function ChatArea({
 29→  workspace,
 30→  workspaceChatPanelRef,
 31→  onCreatePRHandlerChange,
 32→  onSendAgentMessageHandlerChange,
 33→  onCollapseChatPanel,
 34→}: ChatAreaProps) {
 35→  const {
 36→    tabs,
 37→    activeTabId,
 38→    activeTab,
 39→    closedTabs,
 40→    handleTabChange,
 41→    handleTabClose,
 42→    handleTabAdd,
 43→    handleTabReorder,
 44→    handleTabRestore,
 45→    updateChatTabAgentType,
 46→    markChatTabStarted,
 47→  } = useChatTabs({
 48→    workspaceId: workspace.id,
 49→    activeSessionId: workspace.current_session_id,
 50→  });
 51→
 52→  // Resolve sessionId: tab's own session, falling back to workspace's active session
 53→  const tabSessionId = activeTab?.data?.sessionId || workspace.current_session_id;
 54→
 55→  // Per-tab working status: subscribes to each chat tab's session detail cache
 56→  // so each tab's spinner reflects its own session's status (not the workspace's
 57→  // single session_status which breaks with multiple tabs).
 58→  const chatSessionIds = useMemo(
 59→    () => tabs.filter((t) => t.data?.sessionId).map((t) => t.data!.sessionId!),
 60→    [tabs]
 61→  );
 62→  const workingSessionIds = useWorkingSessionIds(chatSessionIds);
 63→
 64→  return (
 65→    <div className="flex h-full min-w-0 flex-1 flex-col overflow-hidden">
 66→      <MainContentTabBar
 67→        tabs={tabs}
 68→        activeTabId={activeTabId}
 69→        workingSessionIds={workingSessionIds}
 70→        onTabChange={handleTabChange}
 71→        onTabClose={handleTabClose}
 72→        onTabAdd={handleTabAdd}
 73→        onTabReorder={handleTabReorder}
 74→        closedTabs={closedTabs}
 75→        onTabRestore={handleTabRestore}
 76→        onCollapseChatPanel={onCollapseChatPanel}
 77→      />
 78→
 79→      <div className="flex min-h-0 flex-1 flex-col overflow-hidden">
 80→        {tabSessionId && (
 81→          <SessionPanel
 82→            key={tabSessionId}
 83→            ref={workspaceChatPanelRef}
 84→            sessionId={tabSessionId}
 85→            workspaceId={workspace.id}
 86→            workspacePath={workspace.workspace_path}
 87→            workspaceRepoName={workspace.repo_name}
 88→            workspaceParentBranch={workspace.git_target_branch}
 89→            workspaceDefaultBranch={workspace.git_default_branch}
 90→            isFirstSession={workspace.latest_message_sent_at === null}
 91→            embedded={true}
 92→            initialModel={activeTab?.data?.initialModel}
 93→            onAgentTypeChange={(agentType) =>
 94→              activeTab && updateChatTabAgentType(activeTab.id, agentType)
 95→            }
 96→            onSessionStarted={() => activeTab && markChatTabStarted(activeTab.id)}
 97→            onOpenNewTab={handleTabAdd}
 98→            onCreatePR={(handler) => onCreatePRHandlerChange(() => handler)}
 99→            onSendAgentMessage={(handler) => onSendAgentMessageHandlerChange(() => handler)}
100→          />
