103→        {/* Workspace still initializing — show the same empty state with init progress */}
104→        {!tabSessionId && (
105→          <WorkspaceEmptyState
106→            repoName={workspace.repo_name}
107→            parentBranch={workspace.git_target_branch}
108→            isFirstSession={true}
109→            initializing={workspace.state === "initializing"}
110→            initStep={workspace.init_stage}
111→          />
112→        )}
113→      </div>
114→    </div>
115→  );
116→}
